import{_ as a,o as i,c as o,ag as s}from"./chunks/framework.PErH1-Uo.js";const h=JSON.parse('{"title":"🌐 Cálculo de Dirección IPv6 Link-local usando SLAAC + EUI-64","description":"","frontmatter":{},"headers":[],"relativePath":"redes/ipv6/ipv6_slaac.md","filePath":"redes/ipv6/ipv6_slaac.md","lastUpdated":1775410727000}'),n={name:"redes/ipv6/ipv6_slaac.md"};function t(r,e,l,d,c,u){return i(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="🌐-calculo-de-direccion-ipv6-link-local-usando-slaac-eui-64" tabindex="-1">🌐 Cálculo de Dirección IPv6 Link-local usando SLAAC + EUI-64 <a class="header-anchor" href="#🌐-calculo-de-direccion-ipv6-link-local-usando-slaac-eui-64" aria-label="Permalink to &quot;🌐 Cálculo de Dirección IPv6 Link-local usando SLAAC + EUI-64&quot;">​</a></h1><p>Vamos a calcular la dirección IPv6 de enlace local (<code>link-local</code>) a partir de una dirección MAC, usando <strong>SLAAC</strong> y el método <strong>EUI-64</strong>.</p><h2 id="direccion-mac-de-ejemplo" tabindex="-1">Dirección MAC de ejemplo <a class="header-anchor" href="#direccion-mac-de-ejemplo" aria-label="Permalink to &quot;Dirección MAC de ejemplo&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>D2:4F:23:1A:5B:9C</span></span></code></pre></div><hr><h2 id="paso-1-separar-en-dos-mitades" tabindex="-1">Paso 1: Separar en dos mitades <a class="header-anchor" href="#paso-1-separar-en-dos-mitades" aria-label="Permalink to &quot;Paso 1: Separar en dos mitades&quot;">​</a></h2><p>Primera mitad: <code>D2:4F:23</code><br> Segunda mitad: <code>1A:5B:9C</code></p><hr><h2 id="paso-2-insertar-la-secuencia-eui-64-ff-fe-en-el-medio" tabindex="-1">Paso 2: Insertar la secuencia EUI-64 <code>FF:FE</code> en el medio <a class="header-anchor" href="#paso-2-insertar-la-secuencia-eui-64-ff-fe-en-el-medio" aria-label="Permalink to &quot;Paso 2: Insertar la secuencia EUI-64 `FF:FE` en el medio&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>D2:4F:23:FF:FE:1A:5B:9C</span></span></code></pre></div><hr><h2 id="paso-3-invertir-el-bit-u-l-del-primer-byte-explicacion-al-final" tabindex="-1">Paso 3: Invertir el bit U/L del primer byte (Explicación al final) <a class="header-anchor" href="#paso-3-invertir-el-bit-u-l-del-primer-byte-explicacion-al-final" aria-label="Permalink to &quot;Paso 3: Invertir el bit U/L del primer byte (Explicación al final)&quot;">​</a></h2><ul><li>Primer byte: <code>D2</code> → binario: <code>11010010</code></li><li>Invertimos el 7.º bit (U/L): <code>11010010</code> → <code>11010000</code> → <code>D0</code></li></ul><p>Nueva secuencia:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>D0:4F:23:FF:FE:1A:5B:9C</span></span></code></pre></div><hr><h2 id="paso-4-anadir-el-prefijo-de-enlace-local-fe80-64" tabindex="-1">Paso 4: Añadir el prefijo de enlace local <code>fe80::/64</code> <a class="header-anchor" href="#paso-4-anadir-el-prefijo-de-enlace-local-fe80-64" aria-label="Permalink to &quot;Paso 4: Añadir el prefijo de enlace local `fe80::/64`&quot;">​</a></h2><p>La dirección IPv6 completa:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fe80::d04f:23ff:fe1a:5b9c</span></span></code></pre></div><h2 id="resultado-final" tabindex="-1">Resultado final <a class="header-anchor" href="#resultado-final" aria-label="Permalink to &quot;Resultado final&quot;">​</a></h2><p><strong>Dirección IPv6 link-local</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fe80::d04f:23ff:fe1a:5b9c</span></span></code></pre></div><h2 id="❓-cuestiones-adicionales-¿por-que-el-bit-u-l-esta-invertido-en-eui-64" tabindex="-1">❓ Cuestiones Adicionales: ¿Por qué el bit U/L está invertido en EUI-64? <a class="header-anchor" href="#❓-cuestiones-adicionales-¿por-que-el-bit-u-l-esta-invertido-en-eui-64" aria-label="Permalink to &quot;❓ Cuestiones Adicionales: ¿Por qué el bit U/L está invertido en EUI-64?&quot;">​</a></h2><h2 id="🧩-¿que-es-el-bit-u-l" tabindex="-1">🧩 ¿Qué es el bit U/L? <a class="header-anchor" href="#🧩-¿que-es-el-bit-u-l" aria-label="Permalink to &quot;🧩 ¿Qué es el bit U/L?&quot;">​</a></h2><p>El bit <strong>U/L (Universal/Local)</strong> es el <strong>7º bit del primer byte</strong> de una dirección MAC o del identificador de interfaz en IPv6.</p><ul><li><code>0</code> → <strong>Universal</strong>: dirección asignada por el fabricante (única globalmente)</li><li><code>1</code> → <strong>Local</strong>: dirección creada localmente (por software o manualmente)</li></ul><p>Por ejemplo:<br><code>E4:7C:F9:...</code><br> → Primer byte <code>E4</code> = <code>11100100</code><br> → 7º bit es <code>0</code> → <strong>Universal</strong></p><h2 id="🔄-¿por-que-se-invierte-este-bit-al-usar-eui-64" tabindex="-1">🔄 ¿Por qué se invierte este bit al usar EUI-64? <a class="header-anchor" href="#🔄-¿por-que-se-invierte-este-bit-al-usar-eui-64" aria-label="Permalink to &quot;🔄 ¿Por qué se invierte este bit al usar EUI-64?&quot;">​</a></h2><p>Cuando se construye una dirección IPv6 mediante <strong>SLAAC y EUI-64</strong>, se <strong>invierte el bit U/L</strong> para indicar que la dirección fue <strong>generada automáticamente</strong> y <strong>no asignada universalmente</strong>.</p><p>Esto es parte del estándar IPv6 para diferenciar entre:</p><ul><li>Direcciones generadas automáticamente (con U/L = <code>1</code>)</li><li>Direcciones MAC originales (con U/L = <code>0</code> si eran universales)</li></ul><h2 id="🛠-ejemplo-paso-a-paso" tabindex="-1">🛠 Ejemplo paso a paso <a class="header-anchor" href="#🛠-ejemplo-paso-a-paso" aria-label="Permalink to &quot;🛠 Ejemplo paso a paso&quot;">​</a></h2><ol><li><p>MAC original: <code>e4:7c:f9:db:b0:14</code><br> → Primer byte: <code>e4</code> = <code>11100100</code> (Pasamos de HEX a BIN)</p></li><li><p>Invertimos el <strong>7º bit</strong> (de izquierda a derecha):<br><code>11100100</code> → <code>11100110</code> = <code>e6</code> (Pasamos de BIN a HEX)</p></li><li><p>Insertamos <code>ff:fe</code> en el medio para formar el identificador de interfaz:<br> Resultado: <code>e6:7c:f9:ff:fe:db:b0:14</code></p></li></ol><h2 id="🧠-¿por-que-se-hace-esto" tabindex="-1">🧠 ¿Por qué se hace esto? <a class="header-anchor" href="#🧠-¿por-que-se-hace-esto" aria-label="Permalink to &quot;🧠 ¿Por qué se hace esto?&quot;">​</a></h2><ul><li>Cumple con los estándares IPv6 de autoconfiguración.</li><li>Permite <strong>distinguir direcciones generadas automáticamente</strong> de las asignadas manualmente.</li><li><strong>Evita colisiones</strong> y facilita la gestión de direcciones en redes IPv6.</li></ul><hr><p>✅ <strong>Resumen</strong>: El bit U/L se invierte al generar direcciones IPv6 con EUI-64 para indicar que se trata de una dirección localmente generada, no una dirección de hardware original.</p><h2 id="🔍-¿que-significa-la-secuencia-ff-fe-en-eui-64" tabindex="-1">🔍 ¿Qué significa la secuencia <code>FF:FE</code> en EUI-64? <a class="header-anchor" href="#🔍-¿que-significa-la-secuencia-ff-fe-en-eui-64" aria-label="Permalink to &quot;🔍 ¿Qué significa la secuencia `FF:FE` en EUI-64?&quot;">​</a></h2><p>La secuencia <code>FF:FE</code> que aparece en el método EUI-64 al generar una dirección IPv6 no es aleatoria, sino que tiene un propósito específico y estándar. Vamos a verlo bien explicado:</p><h2 id="🧩-¿que-es-eui-64" tabindex="-1">🧩 ¿Qué es EUI-64? <a class="header-anchor" href="#🧩-¿que-es-eui-64" aria-label="Permalink to &quot;🧩 ¿Qué es EUI-64?&quot;">​</a></h2><p><strong>EUI-64 (Extended Unique Identifier - 64 bits)</strong> es un método usado en IPv6 para crear un identificador de interfaz de 64 bits a partir de una dirección MAC de 48 bits.</p><p>Como una dirección MAC tiene solo <strong>48 bits</strong>, y se necesitan <strong>64 bits</strong> para una dirección IPv6, se deben añadir <strong>16 bits extra</strong>. Esa ampliación se hace insertando la secuencia <strong><code>FF:FE</code></strong> en el medio de la MAC.</p><h2 id="🔧-¿como-se-usa-ff-fe" tabindex="-1">🔧 ¿Cómo se usa <code>FF:FE</code>? <a class="header-anchor" href="#🔧-¿como-se-usa-ff-fe" aria-label="Permalink to &quot;🔧 ¿Cómo se usa `FF:FE`?&quot;">​</a></h2><h3 id="ejemplo" tabindex="-1">Ejemplo: <a class="header-anchor" href="#ejemplo" aria-label="Permalink to &quot;Ejemplo:&quot;">​</a></h3><ol><li>MAC original:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>a4:23:05:9b:cc:01</span></span></code></pre></div><ol start="2"><li>Dividir en dos partes:</li></ol><ul><li>Primera mitad: <code>a4:23:05</code></li><li>Segunda mitad: <code>9b:cc:01</code></li></ul><ol start="3"><li>Insertar <code>FF:FE</code> en el centro:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>a4:23:05:FF:FE:9b:cc:01</span></span></code></pre></div><ol start="4"><li>Invertir el bit U/L (7º bit del primer byte)</li></ol><ul><li><code>a4</code> = <code>10100100</code> → se convierte en <code>a6</code> = <code>10100110</code></li></ul><h2 id="❓-¿por-que-se-usa-ff-fe" tabindex="-1">❓ ¿Por qué se usa <code>FF:FE</code>? <a class="header-anchor" href="#❓-¿por-que-se-usa-ff-fe" aria-label="Permalink to &quot;❓ ¿Por qué se usa `FF:FE`?&quot;">​</a></h2><ul><li>Es una secuencia <strong>reservada por el IEEE</strong>.</li><li>Asegura que la nueva dirección <strong>no coincida</strong> con una MAC real de 64 bits.</li><li>Permite distinguir que la dirección IPv6 fue <strong>generada automáticamente</strong> usando EUI-64.</li><li>Mantiene la <strong>unicidad</strong> de las direcciones IPv6 derivadas de MACs.</li></ul><h2 id="✅-resumen" tabindex="-1">✅ Resumen <a class="header-anchor" href="#✅-resumen" aria-label="Permalink to &quot;✅ Resumen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Elemento</th><th>Significado</th></tr></thead><tbody><tr><td><code>FF:FE</code></td><td>Secuencia fija para expandir MAC de 48 a 64 bits</td></tr><tr><td>¿Por qué?</td><td>Rellenar bits faltantes y evitar colisiones con MAC reales</td></tr><tr><td>¿Dónde va?</td><td>Entre los 3 primeros y 3 últimos bytes de la MAC</td></tr><tr><td>¿Quién lo define?</td><td>Especificado por el estándar IEEE para EUI-64</td></tr></tbody></table><hr><p>🎓 <strong>Nota</strong>: Este método es parte del proceso de <strong>SLAAC (Stateless Address Autoconfiguration)</strong> en redes IPv6.</p>',58)])])}const b=a(n,[["render",t]]);export{h as __pageData,b as default};
